UPDATE words SET example_en_2 = 'The recommendation algorithm learns from your past choices.', example_ko_2 = '추천 알고리즘은 과거 선택을 바탕으로 학습해요.', example_en_3 = 'He studied algorithms as part of his computer science degree.', example_ko_3 = '그는 컴퓨터 공학 학위 과정에서 알고리즘을 공부했어요.', example_en_4 = 'A sorting algorithm arranges data in a specific order.', example_ko_4 = '정렬 알고리즘은 데이터를 특정 순서로 배열해요.', example_en_5 = 'The algorithm was updated to give more relevant results.', example_ko_5 = '더 관련성 높은 결과를 제공하도록 알고리즘이 업데이트됐어요.' WHERE id = 'w_technology_B1_01';
UPDATE words SET example_en_2 = 'The user interface needs to be more intuitive.', example_ko_2 = '사용자 인터페이스가 더 직관적이어야 해요.', example_en_3 = 'The new interface is much cleaner than the old one.', example_ko_3 = '새 인터페이스는 기존 것보다 훨씬 깔끔해요.', example_en_4 = 'She designed the interface to be accessible to all users.', example_ko_4 = '그녀는 모든 사용자가 접근할 수 있도록 인터페이스를 설계했어요.', example_en_5 = 'The interface was redesigned based on user feedback.', example_ko_5 = '사용자 피드백을 바탕으로 인터페이스가 재설계됐어요.' WHERE id = 'w_technology_B1_02';
UPDATE words SET example_en_2 = 'The database stores millions of customer records.', example_ko_2 = '데이터베이스에는 수백만 건의 고객 기록이 저장되어 있어요.', example_en_3 = 'We need to query the database to get that information.', example_ko_3 = '그 정보를 얻으려면 데이터베이스를 쿼리해야 해요.', example_en_4 = 'The database was corrupted after the system crash.', example_ko_4 = '시스템 충돌 후 데이터베이스가 손상됐어요.', example_en_5 = 'She set up a database to track inventory automatically.', example_ko_5 = '그녀는 재고를 자동으로 추적하기 위해 데이터베이스를 구축했어요.' WHERE id = 'w_technology_B1_03';
UPDATE words SET example_en_2 = 'The server was down for two hours this morning.', example_ko_2 = '오늘 아침 두 시간 동안 서버가 다운됐어요.', example_en_3 = 'All your data is stored on a secure server.', example_ko_3 = '모든 데이터는 안전한 서버에 저장되어 있어요.', example_en_4 = 'The company runs its own server instead of using the cloud.', example_ko_4 = '회사는 클라우드 대신 자체 서버를 운영해요.', example_en_5 = 'A dedicated server improves performance for high-traffic websites.', example_ko_5 = '전용 서버는 트래픽이 많은 웹사이트의 성능을 향상시켜요.' WHERE id = 'w_technology_B1_04';
UPDATE words SET example_en_2 = 'I back up all my work to the cloud automatically.', example_ko_2 = '모든 작업물을 자동으로 클라우드에 백업해요.', example_en_3 = 'Cloud storage makes it easy to access files from any device.', example_ko_3 = '클라우드 스토리지는 어떤 기기에서든 파일에 쉽게 접근할 수 있게 해줘요.', example_en_4 = 'The company moved all its data to the cloud last year.', example_ko_4 = '회사는 작년에 모든 데이터를 클라우드로 이전했어요.', example_en_5 = 'Cloud computing has changed how businesses manage their IT needs.', example_ko_5 = '클라우드 컴퓨팅은 기업이 IT 요구 사항을 관리하는 방식을 바꿔 놓았어요.' WHERE id = 'w_technology_B1_05';
UPDATE words SET example_en_2 = 'She learned to code by watching online tutorials.', example_ko_2 = '그녀는 온라인 튜토리얼을 보며 코딩을 배웠어요.', example_en_3 = 'The code has a bug that is causing the app to crash.', example_ko_3 = '코드에 버그가 있어서 앱이 충돌하고 있어요.', example_en_4 = 'He wrote clean and well-documented code.', example_ko_4 = '그는 깔끔하고 잘 정리된 코드를 작성했어요.', example_en_5 = 'The QR code takes you directly to the website.', example_ko_5 = 'QR 코드를 스캔하면 바로 웹사이트로 연결돼요.' WHERE id = 'w_technology_B1_06';
UPDATE words SET example_en_2 = 'End-to-end encryption protects your messages from being read by others.', example_ko_2 = '종단 간 암호화는 메시지가 다른 사람에게 읽히지 않도록 보호해요.', example_en_3 = 'The company uses strong encryption to protect customer data.', example_ko_3 = '회사는 고객 데이터를 보호하기 위해 강력한 암호화를 사용해요.', example_en_4 = 'Without encryption, your data could be intercepted.', example_ko_4 = '암호화가 없으면 데이터가 가로채질 수 있어요.', example_en_5 = 'The new law requires encryption of all personal health data.', example_ko_5 = '새 법률은 모든 개인 건강 데이터의 암호화를 요구해요.' WHERE id = 'w_technology_B1_07';
UPDATE words SET example_en_2 = 'Cybersecurity has become a top priority for businesses.', example_ko_2 = '사이버 보안이 기업들의 최우선 과제가 됐어요.', example_en_3 = 'She works in cybersecurity and helps companies protect their systems.', example_ko_3 = '그녀는 사이버 보안 분야에서 일하며 기업들이 시스템을 보호하도록 돕고 있어요.', example_en_4 = 'Weak passwords are still one of the biggest cybersecurity risks.', example_ko_4 = '취약한 비밀번호는 여전히 가장 큰 사이버 보안 위험 중 하나예요.', example_en_5 = 'The government increased its cybersecurity budget after the attack.', example_ko_5 = '정부는 공격 이후 사이버 보안 예산을 늘렸어요.' WHERE id = 'w_technology_B1_08';
UPDATE words SET example_en_2 = 'Video calls use a lot of bandwidth.', example_ko_2 = '화상 통화는 많은 대역폭을 사용해요.', example_en_3 = 'Our bandwidth is limited, so please avoid streaming in 4K.', example_ko_3 = '대역폭이 제한되어 있어서 4K 스트리밍은 자제해 주세요.', example_en_4 = 'Higher bandwidth means faster internet speeds.', example_ko_4 = '대역폭이 높을수록 인터넷 속도가 빨라져요.', example_en_5 = 'The network upgrade doubled the available bandwidth.', example_ko_5 = '네트워크 업그레이드로 사용 가능한 대역폭이 두 배가 됐어요.' WHERE id = 'w_technology_B1_09';
UPDATE words SET example_en_2 = 'I spent the whole afternoon debugging the code.', example_ko_2 = '오후 내내 코드를 디버깅하며 보냈어요.', example_en_3 = 'Debugging is often more time-consuming than writing code in the first place.', example_ko_3 = '디버깅은 처음부터 코드를 작성하는 것보다 시간이 더 많이 걸리는 경우가 많아요.', example_en_4 = 'She used a debugging tool to identify the problem.', example_ko_4 = '그녀는 디버깅 도구를 사용해서 문제를 파악했어요.', example_en_5 = 'Good error messages make debugging much easier.', example_ko_5 = '좋은 오류 메시지는 디버깅을 훨씬 쉽게 만들어 줘요.' WHERE id = 'w_technology_B1_10';
UPDATE words SET example_en_2 = 'The team decided to switch to a different framework.', example_ko_2 = '팀은 다른 프레임워크로 전환하기로 결정했어요.', example_en_3 = 'React is a popular JavaScript framework for building apps.', example_ko_3 = 'React는 앱 개발에 인기 있는 자바스크립트 프레임워크예요.', example_en_4 = 'Using a framework speeds up development significantly.', example_ko_4 = '프레임워크를 사용하면 개발 속도가 크게 빨라져요.', example_en_5 = 'The framework handles a lot of the boilerplate code for you.', example_ko_5 = '프레임워크는 많은 보일러플레이트 코드를 대신 처리해 줘요.' WHERE id = 'w_technology_B1_11';
UPDATE words SET example_en_2 = 'We use version control to track changes in our code.', example_ko_2 = '저희는 코드 변경 사항을 추적하기 위해 버전 관리를 사용해요.', example_en_3 = 'Version control allows multiple developers to work on the same project.', example_ko_3 = '버전 관리를 통해 여러 개발자가 동일한 프로젝트에 동시에 작업할 수 있어요.', example_en_4 = 'Git is the most widely used version control system.', example_ko_4 = 'Git은 가장 널리 사용되는 버전 관리 시스템이에요.', example_en_5 = 'She committed her changes to version control before going home.', example_ko_5 = '그녀는 퇴근 전에 변경 사항을 버전 관리에 커밋했어요.' WHERE id = 'w_technology_B1_12';
UPDATE words SET example_en_2 = 'The deployment went smoothly with no downtime.', example_ko_2 = '다운타임 없이 배포가 원활하게 진행됐어요.', example_en_3 = 'We schedule deployments for late at night to minimise disruption.', example_ko_3 = '서비스 중단을 최소화하기 위해 배포를 늦은 밤에 예약해요.', example_en_4 = 'The new feature is ready for deployment.', example_ko_4 = '새 기능이 배포할 준비가 됐어요.', example_en_5 = 'Automated deployment reduces the risk of human error.', example_ko_5 = '자동화된 배포는 사람의 실수 위험을 줄여줘요.' WHERE id = 'w_technology_B1_13';
UPDATE words SET example_en_2 = 'The company''s firewall blocks access to social media.', example_ko_2 = '회사의 방화벽이 소셜 미디어 접근을 차단해요.', example_en_3 = 'A firewall is your first line of defence against hackers.', example_ko_3 = '방화벽은 해커에 대한 첫 번째 방어선이에요.', example_en_4 = 'Configure the firewall settings carefully to avoid blocking legitimate traffic.', example_ko_4 = '정상적인 트래픽이 차단되지 않도록 방화벽 설정을 신중하게 구성하세요.', example_en_5 = 'The firewall detected and blocked an intrusion attempt.', example_ko_5 = '방화벽이 침입 시도를 탐지하고 차단했어요.' WHERE id = 'w_technology_B1_14';
UPDATE words SET example_en_2 = 'There''s a bug in the checkout process — users can''t complete their orders.', example_ko_2 = '결제 과정에 버그가 있어서 사용자들이 주문을 완료할 수 없어요.', example_en_3 = 'The team is working on fixing the bug as fast as they can.', example_ko_3 = '팀이 최대한 빨리 버그를 수정하고 있어요.', example_en_4 = 'I found a bug where the app crashes when you rotate the screen.', example_ko_4 = '화면을 회전할 때 앱이 충돌하는 버그를 발견했어요.', example_en_5 = 'The bug was introduced in the last update.', example_ko_5 = '그 버그는 마지막 업데이트에서 발생했어요.' WHERE id = 'w_technology_B1_15';
UPDATE words SET example_en_2 = 'The developer released a patch to fix the security vulnerability.', example_ko_2 = '개발자가 보안 취약점을 수정하는 패치를 출시했어요.', example_en_3 = 'Install the patch as soon as possible to protect your system.', example_ko_3 = '시스템을 보호하려면 가능한 한 빨리 패치를 설치해 주세요.', example_en_4 = 'The patch broke a different feature — so now we have a new problem.', example_ko_4 = '패치가 다른 기능을 망가뜨려서 새로운 문제가 생겼어요.', example_en_5 = 'They pushed a small patch to fix the login issue.', example_ko_5 = '로그인 문제를 수정하기 위해 소규모 패치를 배포했어요.' WHERE id = 'w_technology_B1_16';
UPDATE words SET example_en_2 = 'HTTP is the protocol used to transfer data on the web.', example_ko_2 = 'HTTP는 웹에서 데이터를 전송하는 데 사용되는 프로토콜이에요.', example_en_3 = 'The two systems couldn''t communicate because they use different protocols.', example_ko_3 = '두 시스템은 서로 다른 프로토콜을 사용해서 통신할 수 없었어요.', example_en_4 = 'Follow the correct protocol to ensure secure data transfer.', example_ko_4 = '안전한 데이터 전송을 보장하려면 올바른 프로토콜을 따라 주세요.', example_en_5 = 'The new protocol is faster and more secure than the old one.', example_ko_5 = '새 프로토콜은 기존 것보다 더 빠르고 안전해요.' WHERE id = 'w_technology_B1_17';
UPDATE words SET example_en_2 = 'The browser cache stores website data to load pages faster.', example_ko_2 = '브라우저 캐시는 페이지를 더 빠르게 로드하기 위해 웹사이트 데이터를 저장해요.', example_en_3 = 'Try clearing your cache if the website isn''t loading properly.', example_ko_3 = '웹사이트가 제대로 로드되지 않으면 캐시를 지워 보세요.', example_en_4 = 'The cache helps reduce the number of requests to the server.', example_ko_4 = '캐시는 서버에 대한 요청 횟수를 줄이는 데 도움이 돼요.', example_en_5 = 'Outdated cache data can sometimes cause display problems.', example_ko_5 = '오래된 캐시 데이터는 때때로 표시 문제를 일으킬 수 있어요.' WHERE id = 'w_technology_B1_18';
UPDATE words SET example_en_2 = 'The app uses an API to pull in real-time weather data.', example_ko_2 = '앱은 API를 사용해서 실시간 날씨 데이터를 가져와요.', example_en_3 = 'You need an API key to access this service.', example_ko_3 = '이 서비스에 접근하려면 API 키가 필요해요.', example_en_4 = 'The API allows different applications to communicate with each other.', example_ko_4 = 'API는 서로 다른 애플리케이션이 서로 통신할 수 있게 해줘요.', example_en_5 = 'We integrated a payment API to handle transactions securely.', example_ko_5 = '거래를 안전하게 처리하기 위해 결제 API를 통합했어요.' WHERE id = 'w_technology_B1_19';
UPDATE words SET example_en_2 = 'The code is stored in a private repository on GitHub.', example_ko_2 = '코드는 GitHub의 비공개 저장소에 저장되어 있어요.', example_en_3 = 'Clone the repository to get a local copy of the code.', example_ko_3 = '코드의 로컬 사본을 얻으려면 저장소를 클론하세요.', example_en_4 = 'She made the repository public so others could contribute.', example_ko_4 = '그녀는 다른 사람들도 기여할 수 있도록 저장소를 공개했어요.', example_en_5 = 'The repository has over ten thousand stars on GitHub.', example_ko_5 = '해당 저장소는 GitHub에서 1만 개 이상의 스타를 받았어요.' WHERE id = 'w_technology_B1_20';
UPDATE words SET example_en_2 = 'We''re adding a new feature that lets you filter results by date.', example_ko_2 = '날짜별로 결과를 필터링할 수 있는 새 기능을 추가하고 있어요.', example_en_3 = 'The most requested feature is offline mode.', example_ko_3 = '가장 많이 요청된 기능은 오프라인 모드예요.', example_en_4 = 'This feature was designed based on user feedback.', example_ko_4 = '이 기능은 사용자 피드백을 바탕으로 설계됐어요.', example_en_5 = 'She turned off the feature because it used too much battery.', example_ko_5 = '배터리를 너무 많이 사용해서 그녀는 그 기능을 껐어요.' WHERE id = 'w_technology_B1_21';
UPDATE words SET example_en_2 = 'The app is available on all major platforms.', example_ko_2 = '이 앱은 모든 주요 플랫폼에서 사용할 수 있어요.', example_en_3 = 'Which platform does your team use for project management?', example_ko_3 = '팀에서 프로젝트 관리에 어떤 플랫폼을 사용하세요?', example_en_4 = 'The platform connects buyers and sellers directly.', example_ko_4 = '이 플랫폼은 구매자와 판매자를 직접 연결해요.', example_en_5 = 'She built her business entirely on this e-commerce platform.', example_ko_5 = '그녀는 이 전자상거래 플랫폼에서 사업을 완전히 구축했어요.' WHERE id = 'w_technology_B1_22';
UPDATE words SET example_en_2 = 'You don''t have permission to view this file.', example_ko_2 = '이 파일을 볼 권한이 없어요.', example_en_3 = 'The app is asking for permission to access your camera.', example_ko_3 = '앱에서 카메라 접근 권한을 요청하고 있어요.', example_en_4 = 'Only administrators have permission to edit the settings.', example_ko_4 = '관리자만 설정을 수정할 권한이 있어요.', example_en_5 = 'She granted the new team member permission to access the shared drive.', example_ko_5 = '그녀는 새 팀원에게 공유 드라이브 접근 권한을 부여했어요.' WHERE id = 'w_technology_B1_23';
UPDATE words SET example_en_2 = 'Your calendar will sync automatically across all your devices.', example_ko_2 = '캘린더가 모든 기기에서 자동으로 동기화돼요.', example_en_3 = 'The sync failed because the devices weren''t on the same network.', example_ko_3 = '기기들이 같은 네트워크에 있지 않아서 동기화에 실패했어요.', example_en_4 = 'Turn on sync to keep your settings the same on every device.', example_ko_4 = '모든 기기에서 동일한 설정을 유지하려면 동기화를 켜 두세요.', example_en_5 = 'The app syncs your data in the background without interrupting you.', example_ko_5 = '앱은 방해 없이 백그라운드에서 데이터를 동기화해요.' WHERE id = 'w_technology_B1_24';
UPDATE words SET example_en_2 = 'The company''s systems were infected with malware.', example_ko_2 = '회사의 시스템이 악성 소프트웨어에 감염됐어요.', example_en_3 = 'Never click on suspicious links — they might install malware.', example_ko_3 = '의심스러운 링크를 클릭하지 마세요. 악성 소프트웨어가 설치될 수 있어요.', example_en_4 = 'The malware stole personal data from thousands of users.', example_ko_4 = '악성 소프트웨어가 수천 명의 사용자에게서 개인 데이터를 훔쳤어요.', example_en_5 = 'Keep your antivirus updated to protect against the latest malware.', example_ko_5 = '최신 악성 소프트웨어로부터 보호받으려면 바이러스 백신을 최신 상태로 유지하세요.' WHERE id = 'w_technology_B1_25';
UPDATE words SET example_en_2 = 'Personal data must be handled carefully under the new regulations.', example_ko_2 = '개인 데이터는 새로운 규정에 따라 신중하게 처리해야 해요.', example_en_3 = 'We analyze data to better understand our customers'' needs.', example_ko_3 = '고객의 요구를 더 잘 이해하기 위해 데이터를 분석해요.', example_en_4 = 'The data shows that most users prefer the dark mode.', example_ko_4 = '데이터에 따르면 대부분의 사용자가 다크 모드를 선호해요.', example_en_5 = 'Without enough data, it''s hard to draw reliable conclusions.', example_ko_5 = '충분한 데이터가 없으면 신뢰할 수 있는 결론을 내리기 어려워요.' WHERE id = 'w_technology_B1_26';
UPDATE words SET example_en_2 = 'We need a solution that is scalable as our user base grows.', example_ko_2 = '사용자 기반이 늘어남에 따라 확장 가능한 솔루션이 필요해요.', example_en_3 = 'The architecture is designed to be scalable from the start.', example_ko_3 = '아키텍처는 처음부터 확장 가능하도록 설계됐어요.', example_en_4 = 'Cloud services make it easier to build scalable applications.', example_ko_4 = '클라우드 서비스 덕분에 확장 가능한 애플리케이션을 더 쉽게 구축할 수 있어요.', example_en_5 = 'A scalable system can handle sudden spikes in traffic without crashing.', example_ko_5 = '확장 가능한 시스템은 갑작스러운 트래픽 급증에도 다운되지 않고 처리할 수 있어요.' WHERE id = 'w_technology_B1_27';
UPDATE words SET example_en_2 = 'The integration between the two systems took several weeks.', example_ko_2 = '두 시스템 간의 통합에 몇 주가 걸렸어요.', example_en_3 = 'She led the integration of the new payment system.', example_ko_3 = '그녀는 새 결제 시스템의 통합 작업을 이끌었어요.', example_en_4 = 'Seamless integration is key to a good user experience.', example_ko_4 = '매끄러운 통합은 좋은 사용자 경험의 핵심이에요.', example_en_5 = 'The app offers integration with most popular productivity tools.', example_ko_5 = '이 앱은 대부분의 인기 있는 생산성 도구와의 통합을 지원해요.' WHERE id = 'w_technology_B1_28';
UPDATE words SET example_en_2 = 'We completed the sprint two days ahead of schedule.', example_ko_2 = '예정보다 이틀 앞서 스프린트를 완료했어요.', example_en_3 = 'Each sprint lasts two weeks in our development cycle.', example_ko_3 = '저희 개발 주기에서 각 스프린트는 2주씩 진행돼요.', example_en_4 = 'The sprint review showed that we hit all our targets.', example_ko_4 = '스프린트 리뷰 결과 모든 목표를 달성했다는 것을 확인했어요.', example_en_5 = 'She added the new task to the backlog for the next sprint.', example_ko_5 = '그녀는 다음 스프린트를 위해 백로그에 새 작업을 추가했어요.' WHERE id = 'w_technology_B1_29';
UPDATE words SET example_en_2 = 'Many companies build their products on open source software.', example_ko_2 = '많은 기업이 오픈 소스 소프트웨어를 기반으로 제품을 개발해요.', example_en_3 = 'The project became widely popular after going open source.', example_ko_3 = '프로젝트가 오픈 소스로 전환된 후 널리 인기를 얻었어요.', example_en_4 = 'She contributes to several open source projects in her spare time.', example_ko_4 = '그녀는 여가 시간에 여러 오픈 소스 프로젝트에 기여해요.', example_en_5 = 'The open source community helped fix the bug within hours.', example_ko_5 = '오픈 소스 커뮤니티 덕분에 몇 시간 안에 버그가 수정됐어요.' WHERE id = 'w_technology_B1_30';
UPDATE words SET example_en_2 = 'She wrote a script to automate the data entry process.', example_ko_2 = '그녀는 데이터 입력 프로세스를 자동화하는 스크립트를 작성했어요.', example_en_3 = 'Run the script to set up the development environment.', example_ko_3 = '개발 환경을 구성하려면 스크립트를 실행하세요.', example_en_4 = 'The script failed because of a missing dependency.', example_ko_4 = '필요한 의존성이 없어서 스크립트가 실패했어요.', example_en_5 = 'He modified the script to handle larger datasets.', example_ko_5 = '그는 더 큰 데이터 세트를 처리하도록 스크립트를 수정했어요.' WHERE id = 'w_technology_B1_31';
UPDATE words SET example_en_2 = 'High latency makes online gaming very frustrating.', example_ko_2 = '높은 레이턴시 때문에 온라인 게임이 너무 답답해요.', example_en_3 = 'The team is working to reduce latency in the app.', example_ko_3 = '팀은 앱의 레이턴시를 줄이기 위해 노력하고 있어요.', example_en_4 = 'Latency under fifty milliseconds is generally acceptable for most applications.', example_ko_4 = '대부분의 애플리케이션에서 50밀리초 미만의 레이턴시는 일반적으로 허용 가능한 수준이에요.', example_en_5 = 'Edge servers help reduce latency by moving data closer to users.', example_ko_5 = '엣지 서버는 데이터를 사용자 가까이 이동시켜 레이턴시를 줄이는 데 도움이 돼요.' WHERE id = 'w_technology_B1_32';
UPDATE words SET example_en_2 = 'Check the server log to find out when the error occurred.', example_ko_2 = '오류가 발생한 시점을 확인하려면 서버 로그를 확인하세요.', example_en_3 = 'The system automatically logs all user activity.', example_ko_3 = '시스템은 모든 사용자 활동을 자동으로 기록해요.', example_en_4 = 'Clear the log files to free up disk space.', example_ko_4 = '디스크 공간을 확보하려면 로그 파일을 지워 주세요.', example_en_5 = 'She analyzed the logs to trace the root cause of the problem.', example_ko_5 = '그녀는 문제의 근본 원인을 추적하기 위해 로그를 분석했어요.' WHERE id = 'w_technology_B1_33';
UPDATE words SET example_en_2 = 'The API uses a token for authentication instead of a password.', example_ko_2 = 'API는 비밀번호 대신 인증을 위해 토큰을 사용해요.', example_en_3 = 'Your token expires after twenty-four hours.', example_ko_3 = '토큰은 24시간 후에 만료돼요.', example_en_4 = 'Never share your access token with anyone.', example_ko_4 = '액세스 토큰을 절대 다른 사람과 공유하지 마세요.', example_en_5 = 'The system generated a new token every time she logged in.', example_ko_5 = '시스템은 그녀가 로그인할 때마다 새 토큰을 생성했어요.' WHERE id = 'w_technology_B1_34';
UPDATE words SET example_en_2 = 'The webhook sends a notification as soon as a payment is received.', example_ko_2 = '결제가 완료되는 즉시 웹훅이 알림을 전송해요.', example_en_3 = 'Set up a webhook so your app reacts to events in real time.', example_ko_3 = '앱이 실시간으로 이벤트에 반응하도록 웹훅을 설정해 주세요.', example_en_4 = 'The webhook failed because the endpoint URL was incorrect.', example_ko_4 = '엔드포인트 URL이 잘못되어 웹훅이 실패했어요.', example_en_5 = 'We use webhooks to trigger automated workflows.', example_ko_5 = '자동화된 워크플로우를 실행하기 위해 웹훅을 사용해요.' WHERE id = 'w_technology_B1_35';

