UPDATE words SET example_en_2 = 'Artificial intelligence is being used to improve medical diagnosis.', example_ko_2 = '인공지능이 의료 진단 향상에 활용되고 있어요.', example_en_3 = 'The company invested heavily in artificial intelligence research.', example_ko_3 = '회사는 인공지능 연구에 많은 투자를 했어요.', example_en_4 = 'Artificial intelligence can process vast amounts of data in seconds.', example_ko_4 = '인공지능은 수초 안에 방대한 양의 데이터를 처리할 수 있어요.', example_en_5 = 'There are serious ethical concerns about the use of artificial intelligence in hiring.', example_ko_5 = '채용 과정에서의 인공지능 활용에 대한 심각한 윤리적 우려가 있어요.' WHERE id = 'w_technology_B2_01';
UPDATE words SET example_en_2 = 'Machine learning allows computers to improve through experience.', example_ko_2 = '머신 러닝은 컴퓨터가 경험을 통해 발전할 수 있게 해줘요.', example_en_3 = 'She is studying machine learning to transition into data science.', example_ko_3 = '그녀는 데이터 과학으로 커리어를 전환하기 위해 머신 러닝을 공부하고 있어요.', example_en_4 = 'Machine learning models need large amounts of training data.', example_ko_4 = '머신 러닝 모델은 대량의 훈련 데이터가 필요해요.', example_en_5 = 'The fraud detection system uses machine learning to identify suspicious transactions.', example_ko_5 = '사기 탐지 시스템은 의심스러운 거래를 식별하기 위해 머신 러닝을 사용해요.' WHERE id = 'w_technology_B2_02';
UPDATE words SET example_en_2 = 'Automation has significantly reduced the time needed to process orders.', example_ko_2 = '자동화 덕분에 주문 처리에 필요한 시간이 크게 줄었어요.', example_en_3 = 'The factory introduced automation to reduce production costs.', example_ko_3 = '공장은 생산 비용을 줄이기 위해 자동화를 도입했어요.', example_en_4 = 'Many repetitive tasks are now handled through automation.', example_ko_4 = '많은 반복적인 작업들이 이제 자동화를 통해 처리되고 있어요.', example_en_5 = 'She worries that automation will make her job obsolete.', example_ko_5 = '그녀는 자동화로 인해 자신의 직업이 사라질까봐 걱정해요.' WHERE id = 'w_technology_B2_03';
UPDATE words SET example_en_2 = 'Blockchain technology makes transactions transparent and tamper-proof.', example_ko_2 = '블록체인 기술은 거래를 투명하고 변조 불가능하게 만들어요.', example_en_3 = 'Some companies are using blockchain to track their supply chains.', example_ko_3 = '일부 기업들은 공급망을 추적하기 위해 블록체인을 사용하고 있어요.', example_en_4 = 'He wrote his thesis on the potential applications of blockchain.', example_ko_4 = '그는 블록체인의 잠재적 응용에 관한 논문을 작성했어요.', example_en_5 = 'Blockchain could reduce fraud in financial transactions significantly.', example_ko_5 = '블록체인은 금융 거래의 사기를 크게 줄일 수 있어요.' WHERE id = 'w_technology_B2_04';
UPDATE words SET example_en_2 = 'IoT devices in the home can be controlled from your phone.', example_ko_2 = '가정 내 IoT 기기는 스마트폰으로 제어할 수 있어요.', example_en_3 = 'The hospital uses IoT sensors to monitor patients remotely.', example_ko_3 = '병원은 환자를 원격으로 모니터링하기 위해 IoT 센서를 사용해요.', example_en_4 = 'Security is a major concern with IoT devices.', example_ko_4 = 'IoT 기기의 보안은 중요한 관심사예요.', example_en_5 = 'She set up an IoT system to monitor energy usage in her home.', example_ko_5 = '그녀는 가정의 에너지 사용량을 모니터링하기 위해 IoT 시스템을 구축했어요.' WHERE id = 'w_technology_B2_05';
